import{_ as r}from"./plugin-vue_export-helper.21dcd24c.js";import{o as b,b as t,ac as e}from"./framework.4684342f.js";const T='{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E09\u7AE0","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E09\u7AE0","date":"2018-06-04T10:01:18.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180604_\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E09\u7AE0.md","lastUpdated":1679296000876}',p={},_=e('<p><img src="https://farm2.staticflickr.com/1747/27862285357_d39b7b3a53.jpg" alt=""></p><p>\u672C\u7AE0\u6C92\u6709\u63D0\u4F46\u4EE5\u7406\uFF0C\u5728\u63CF\u8FF0\u4E09\u500B\u670B\u53CB\u5C0D\u4FE1\u4EF0\u5805\u5B9A\u7684\u614B\u5EA6<br> \u7E31\u4F7F\u795E\u6C92\u6709\u51FA\u624B\uFF0C\u4E09\u500B\u670B\u53CB\u62B1\u8457\u5373\u6216\u4E0D\u7136\u6B89\u9053\u7684\u6C7A\u5FC3<br> \u4E5F\u4E0D\u9858\u5C48\u819D\u4E0B\u62DC\u738B\u7684\u91D1\u50CF\uFF0C\u4E0D\u59A5\u5354\u8207\u4FE1\u4EF0\u4E0A\u7684\u885D\u7A81<br></p><p>\u672C\u7AE0\u53EF\u770B\u5230\u7684\u5167\u5BB9\uFF0C\u6574\u7406\u5982\u4E0B\uFF1A</p><ol><li><p>\u4F46\u4EE5\u7406\u670B\u53CB\u7121\u529F\u53D7\u797F\uFF0C\u906D\u53D7\u8FE6\u52D2\u5E95\u8853\u58EB\u5FCC\u5992<br> \u53EF\u80FD\u4F46\u4EE5\u7406\u53CA\u4E09\u500B\u670B\u53CB\u7686\u662F\u88AB\u64C4\u5916\u90A6\u4EBA(\u6230\u4FD8)<br> \u53CD\u5012\u5B98\u4F4D\u6BD4\u672C\u570B\u4EBA\u9084\u9AD8\uFF0C\u800C\u9019\u4E9B\u8853\u58EB\u4E5F\u8EAB\u61F7\u7D55\u6280<br> \u8FE6\u52D2\u5E95\u540C\u6642\u662F\u5DF4\u6BD4\u502B\u4EBA\uFF0C\u61C9\u4EAB\u6709\u6700\u9AD8\u6B0A\u5229<br> \u8981\u5C01\u5B98\u52A0\u7235\uFF0C\u570B\u738B\u4E5F\u7576\u5F9E\u672C\u570B\u4EBA\u505A\u8D77\uFF0C\u600E\u8B93\u7D66\u5916\u4EBA<br> (\u65E5\u64DA\u6642\u4EE3\uFF0C\u65E5\u672C\u4EBA\u5FF5\u4E00\u6D41\u5B78\u6821\uFF0C\u53F0\u7063\u4EBA\u53EA\u80FD\u5538\u6B21\u7B49\u7684)<br> \u4F46\u4EE5\u7406\u53CA\u4E09\u4F4D\u670B\u53CB\u770B\u5728\u672C\u570B\u4EBA\u773C\u88E1\uFF0C\u65E9\u5DF2\u6068\u5F97\u7259\u7662\u7662\u7684</p></li><li><p>\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\uFF0C\u6027\u683C\u4E56\u821B\uFF0C\u51F6\u72E0\u6B98\u66B4<br> \u5728\u738B\u7684\u89E3\u8AAA\u4E4B\u4E0B\uFF0C\u672C\u4F86\u5E0C\u671B\u4F46\u4EE5\u7406\u4E09\u4F4D\u670B\u53CB\u80FD\u63A1\u7D0D\u5EFA\u8B70<br> \u53EA\u8981\u5C0D\u738B\u7684\u91D1\u50CF\u4E0B\u62DC\uFF0C\u5C31\u80FD\u514D\u65BC\u7121\u5984\u4E4B\u707D\uFF0C\u800C\u4E0B\u62DC\u975E\u96E3\u4E8B<br> \u7562\u7ADF\uFF0C\u9019\u4E09\u4F4D\u7684\u5B98\u4F4D\u662F\u738B\u89AA\u53E3\u7B54\u61C9\u4F46\u4EE5\u7406\u7684<br> \u4F46\u738B\u7981\u4E0D\u8D77\u5225\u4EBA\u7684\u9802\u649E\uFF0C\u7121\u8996\u4ED6\u6240\u91CB\u51FA\u7684\u5584\u610F<br> \u53CD\u800C\u5728\u9019\u6642\u9593\u9EDE\uFF0C\u6574\u500B\u60C5\u7DD2\u7206\u767C\uFF0C\u4E00\u767C\u4E0D\u53EF\u6536\u62FE<br> \u9084\u547D\u4EBA\u628A\u706B\u52A0\u70C8\uFF0C\u751A\u81F3\u9023\u62AC\u7684\u4EBA\u90FD\u88AB\u71D2\u6B7B\u4E86<br><br> \u9019\u908A\u770B\u5230\uFF0C\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u662F\u6025\u6027\u5B50\u7684\u4EBA<br> \u60F3\u5230\u751A\u9EBC\u5C31\u505A\u751A\u9EBC\uFF0C\u524D\u4E00\u7AE0\u770B\u5230\u4F46\u4EE5\u7406\u89E3\u5922<br> \u5C31\u5C01\u4F46\u4EE5\u7406\u7BA1\u7406\u5168\u570B\u6240\u6709\u6709\u667A\u6167\u7684\u8853\u58EB<br> \u4F46\u4EE5\u7406\u8ACB\u6C42\u4E09\u500B\u670B\u53CB\uFF0C\u738B\u5FC3\u60C5\u597D\u4E5F\u7ACB\u5373\u7B54\u61C9<br> \u4E09\u500B\u670B\u53CB\u4E0D\u807D\u738B\u7684\u8A71\uFF0C\u7ACB\u5373\u6C96\u6C96\u5927\u6012\uFF0C\u547D\u4EBA\u628A\u7AAF\u52A0\u71B1<br><br> \u800C\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u4E5F\u6F38\u9032\u5F0F\uFF0C\u8D8A\u4F86\u8D8A\u61A4\u6012<br> \u4E00\u958B\u59CB\u88AB\u9802\u649E\uFF0C\u60C5\u7DD2\u662F\u6C96\u6C96\u5927\u6012<br> \u5728\u4F46\u4EE5\u7406\u4E09\u53CB\u4E0D\u9806\u5F9E\u5F8C\uFF0C\u8B8A\u6210\u6012\u6C23\u586B\u80F8\uFF0C\u8B8A\u4E86\u81C9\u8272<br> \u6211\u6709\u9EDE\u61F7\u7591\uFF0C\u9019\u6A23\u5B50\u7684\u4EBA\uFF0C\u8EAB\u5FC3\u72C0\u6CC1\u662F\u4E0D\u662F\u4E0D\u597D<br> \u5F88\u5BB9\u6613\u53D7\u8A00\u8A9E\u3001\u74B0\u5883\u5F71\u97FF\uFF0C\u60C5\u7DD2\u5F88\u5927\u7684\u8D77\u4F0F\u3001\u6CE2\u52D5</p></li><li><p>\u4F46\u4EE5\u7406\u4E09\u500B\u670B\u53CB\uFF0C\u5148\u6709\u4FE1\u5FC3\uFF0C\u5E36\u51FA\u795E\u8E5F<br> \u9019\u7AE0\u4F46\u4EE5\u7406\u4E09\u500B\u670B\u53CB\u8DDF\u524D\u4E00\u7AE0\u4F46\u4EE5\u7406\u5C0D\u795E\u7684\u4FE1\u5FC3\u662F\u4E00\u6A23\u7684<br> \u4ED6\u5011\u6253\u5F9E\u4E00\u958B\u59CB\u5C31\u62B1\u6301\u8457\u4E0D\u8DEA\u62DC\u738B\u7684\u50CF\uFF0C\u5373\u662F\u6709\u751F\u547D\u5B89\u5371<br> \u5728\u738B\u7684\u8A0E\u50F9\u9084\u50F9\u4E2D\uFF0C\u738B\u4E5F\u91CB\u51FA\u5584\u610F\uFF0C\u5411\u4ED6\u5011\u8AAA\u660E<br> \u82E5\u662F\u4FEF\u4F0F\u656C\u62DC\uFF0C\u537B\u9084\u53EF\u4EE5\uFF0C\u96E3\u9053\u662F\u6545\u610F\u7684\u55CE?<br> \u4ED6\u5011\u7684\u56DE\u7B54\u5F88\u5805\u6C7A\uFF0C\u9019\u4EF6\u4E8B\u6211\u5011\u4E0D\u5FC5\u56DE\u7B54\u4F60<br> \u5373\u4FBF\u5982\u6B64\uFF0C\u5728\u706B\u7AAF\u4E2D\uFF0C\u795E\u80FD\u5F9E\u70C8\u706B\u5C31\u4ED6\u5011\u51FA\u4F86<br><span style="color:red;">\u5373\u6216\u4E0D\u7136</span>\uFF0C\u5C31\u7B97\u6C92\u6709\u795E\u8E5F\uFF0C\u795E\u6C92\u6709\u51FA\u624B\uFF0C\u53EF\u80FD\u6B89\u9053<br> \u4E5F\u7D55\u4E0D\u4E8B\u5949\u4F60\u7684\u795E\uFF0C\u4E5F\u4E0D\u656C\u62DC\u4F60\u6240\u7ACB\u7684\u91D1\u50CF<br> \u4E5F\u56E0\u8457\u9019\u6A23\u5B50\u7684\u4FE1\u5FC3\uFF0C\u795E\u6700\u5F8C\u51FA\u624B\uFF0C\u6551\u4ED6\u5011\u812B\u96E2\u706B\u7AAF<br> \u53CD\u800C\u706B\u7AAF\u76F8\u95DC\u5DE5\u4F5C\u4EBA\u54E1\u4F86\u4E0D\u53CA\u9003\u8DD1\uFF0C\u88AB\u70C8\u706B\u71D2\u6B7B</p></li></ol><p>\u554F\u984C\uFF1A</p><ol><li><p>\u795E\u5B50\uFF0C\u662F\u5DF4\u6BD4\u502B\u7684\u795E\uFF0C\u9084\u662F\u7336\u592A\u4EBA\u7684\u4E0A\u5E1D<br> \u65C1\u4EBA\u770B\u5230\u7B2C\u56DB\u500B\u4EBA\uFF0C\u6C92\u6709\u7D91\u7D81\uFF0C\u76F8\u8C8C\u4F3C\u4E4E\u662F\u795E\u5B50<br> \u9019\u908A\u7684\u795E\u5B50\u6307\u7684\u662F\u5DF4\u6BD4\u502B\u591A\u795E\u7947\u4FE1\u4EF0\u7576\u4E2D\u7684\u4E00\u500B\u4EBA<br> \u9084\u662F\u9019\u662F\u4ED6\u5011\u8A8D\u70BA\u7684\u8036\u548C\u83EF\u4E0A\u5E1D\u7684\u795E?</p></li><li><p>\u89D2\u3001\u7B1B\u3001\u7435\u7436\u3001\u7434\u3001\u745F\u3001\u7B19\u548C\u5404\u6A23\u6A02\u5668\u8072\u97F3\uFF0C\u5C31\u7576\u4FEF\u4F0F\u656C\u62DC\u91D1\u50CF<br> \u9019\u908A\u5728\u60F3\u4E00\u500B\u756B\u9762\uFF0C\u9019\u9EBC\u591A\u6A02\u5668\u8072\u97F3\u61C9\u8A72\u883B\u5E38\u807D\u5230\u7684<br> \u4E5F\u5C31\u8AAA\uFF0C\u5DF4\u6BD4\u502B\u4EBA\u7121\u6642\u4E0D\u523B\u5728\u4E0B\u62DC\u738B\u7684\u91D1\u50CF<br> \u53EA\u8981\u7A0D\u5FAE\u4E0D\u8B39\u614E\uFF0C\u53EF\u80FD\u5C31\u88AB\u63ED\u767C\uFF0C\u5F15\u4F86\u6BBA\u982D\u4E4B\u7F6A<br> \u6D3B\u5728\u9019\u6A23\u7684\u74B0\u5883\u88E1\uFF0C\u7CBE\u795E\u58D3\u529B\u61C9\u8A72\u683C\u5916\u7684\u5927</p></li><li><p>\u4F46\u4EE5\u7406\u4E09\u53CB\u539F\u672C\u88AB\u7D91\u7D81\uFF0C\u5F8C\u4F86\u51FA\u706B\u7AAF\u61C9\u8A72\u662F\u9B06\u812B<br> \u9019\u88E1\u4E5F\u5728\u60F3\u4E00\u500B\u756B\u9762\uFF0C\u539F\u672C\u4ED6\u5011\u53EF\u80FD\u662F\u88AB\u6346\u8457\u843D\u5165\u706B\u7AAF<br> \u795E\u5B50\u51FA\u73FE\u7684\u7684\u6642\u5019\uFF0C\u53EA\u6709\u7E69\u5B50\u9B06\u958B(\u71D2\u6389)\uFF0C\u4F46\u5168\u8EAB\u6BEB\u9AEE\u7121\u50B7<br> \u9084\u662F\u795E\u5B50\u5E6B\u5FD9\u89E3\u958B\uFF0C\u7136\u5F8C\u5C31\u5728\u6D3B\u7AAF\u88E1\u81EA\u7531\u8D70\u52D5\uFF0C\u76F4\u5230\u51FA\u706B\u5751</p></li></ol><p>\u5FC3\u5F97<br> \u5728\u5BAE\u4E2D\u4F8D\u5949\u7684\u7336\u592A\u4EBA\uFF0C\u5C0D\u4E0A\u5E1D\u90FD\u662F\u5E36\u8457\u5805\u5B9A\u7684\u4FE1\u5FC3<br> \u65E9\u5DF2\u628A\u751F\u6B7B\u7F6E\u4E4B\u5EA6\u5916\uFF0C\u5373\u4F7F\u9762\u81E8\u5F37\u6B0A\u7684\u8105\u8FEB\u3001\u52F8\u8A98<br> \u9858\u610F\u6301\u5B88\u4FE1\u4EF0\uFF0C\u628A\u795E\u653E\u5728\u7B2C\u4E00\u4F4D\uFF0C\u8B93\u795E\u4F86\u5DE5\u4F5C<br> \u800C\u795E\u8E5F\u7E3D\u5728\u4EBA\uFF0C\u9858\u610F\u8D70\u5411\u4FE1\u5FC3\u4E4B\u8DEF\uFF0C\u795E\u624D\u5E36\u51FA\u4F86\u7684</p>',7),a=[_];function i(l,o,s,c,n,d){return b(),t("div",null,a)}var h=r(p,[["render",i]]);export{T as __pageData,h as default};
